class SQSWorker:
    def __init__(
        self,
        queue_url: str,
        region_name: str = 'us-east-1',
        max_messages: int = 10,
        wait_time_seconds: int = 20,
        visibility_timeout: int = 30
    ):
        self.queue_url = queue_url
        self.max_messages = max_messages
        self.wait_time_seconds = wait_time_seconds
        self.visibility_timeout = visibility_timeout
        self.running = False
        
        self.sqs_client = boto3.client('sqs', region_name=region_name)
        
        self.message_handlers: Dict[str, MessageHandler] = {
            'email': EmailMessageHandler(),
            'data_processing': DataProcessingHandler(),
            'notification': NotificationHandler(),
            'report_generation': ReportGenerationHandler(),
            'image_processing': ImageProcessingHandler(),
        }
        
        self.default_handler = DefaultHandler()
        
        self.stats = {
            'processed': 0,
            'failed': 0,
            'deleted': 0,
            'errors': 0
        }
    
    def register_handler(self, message_type: str, handler: MessageHandler):
        self.message_handlers[message_type] = handler
        logger.info(f"Registered handler for message type: {message_type}")
    
    def register_function_handler(self, message_type: str, handler_func: Callable):
        class FunctionHandler(MessageHandler):
            def __init__(self, func):
                self.func = func
            
            def handle(self, message_data: Dict[str, Any]) -> bool:
                return self.func(message_data)
        
        self.register_handler(message_type, FunctionHandler(handler_func))
    
    def poll_messages(self) -> list:
        try:
            response = self.sqs_client.receive_message(
                QueueUrl=self.queue_url,
                MaxNumberOfMessages=self.max_messages,
                WaitTimeSeconds=self.wait_time_seconds,
                VisibilityTimeout=self.visibility_timeout,
                AttributeNames=['All'],
                MessageAttributeNames=['All']
            )
            
            messages = response.get('Messages', [])
            logger.info(f"Received {len(messages)} messages from queue")
            return messages
            
        except Exception as e:
            logger.error(f"Error polling messages: {str(e)}")
            self.stats['errors'] += 1
            return []
    
    def parse_message(self, message: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        try:
            body = message.get('Body', '{}')
            message_data = json.loads(body)
            
            if 'Message' in message_data:
                message_data = json.loads(message_data['Message'])
            
            return message_data
            
        except json.JSONDecodeError as e:
            logger.error(f"Failed to parse message body: {str(e)}")
            return None
        except Exception as e:
            logger.error(f"Error parsing message: {str(e)}")
            return None
    
    def get_message_type(self, message_data: Dict[str, Any]) -> str:
        message_type = message_data.get('type') or message_data.get('message_type') or message_data.get('event_type')
        
        if not message_type and 'action' in message_data:
            message_type = message_data['action']
        
        return message_type or 'default'
    
    def process_message(self, message: Dict[str, Any]) -> bool:
        try:
            message_id = message.get('MessageId')
            receipt_handle = message.get('ReceiptHandle')
            
            logger.info(f"Processing message: {message_id}")
            
            message_data = self.parse_message(message)
            if message_data is None:
                logger.error(f"Failed to parse message {message_id}")
                self.stats['failed'] += 1
                return False
            
            message_type = self.get_message_type(message_data)
            logger.info(f"Message type: {message_type}")
            
            handler = self.message_handlers.get(message_type, self.default_handler)
            
            success = handler.handle(message_data)
            
            if success:
                self.delete_message(receipt_handle)
                self.stats['processed'] += 1
                logger.info(f"Successfully processed message {message_id}")
                return True
            else:
                logger.error(f"Handler failed for message {message_id}")
                self.stats['failed'] += 1
                return False
                
        except Exception as e:
            logger.error(f"Error processing message: {str(e)}")
            self.stats['errors'] += 1
            return False
    
    def delete_message(self, receipt_handle: str):
        try:
            self.sqs_client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle
            )
            self.stats['deleted'] += 1
            logger.info("Message deleted from queue")
            
        except Exception as e:
            logger.error(f"Error deleting message: {str(e)}")
    
    def change_message_visibility(self, receipt_handle: str, timeout: int):
        try:
            self.sqs_client.change_message_visibility(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle,
                VisibilityTimeout=timeout
            )
            logger.info(f"Changed message visibility to {timeout} seconds")
            
        except Exception as e:
            logger.error(f"Error changing message visibility: {str(e)}")
    
    def get_queue_attributes(self) -> Dict[str, Any]:
        try:
            response = self.sqs_client.get_queue_attributes(
                QueueUrl=self.queue_url,
                AttributeNames=['All']
            )
            return response.get('Attributes', {})
            
        except Exception as e:
            logger.error(f"Error getting queue attributes: {str(e)}")
            return {}
    
    def print_stats(self):
        logger.info("=" * 50)
        logger.info(f"Worker Statistics:")
        logger.info(f"  Processed: {self.stats['processed']}")
        logger.info(f"  Failed: {self.stats['failed']}")
        logger.info(f"  Deleted: {self.stats['deleted']}")
        logger.info(f"  Errors: {self.stats['errors']}")
        logger.info("=" * 50)
    
    def run(self, max_iterations: Optional[int] = None):
        self.running = True
        iteration = 0
        
        logger.info(f"Starting SQS worker for queue: {self.queue_url}")
        
        try:
            while self.running:
                if max_iterations and iteration >= max_iterations:
                    logger.info(f"Reached max iterations: {max_iterations}")
                    break
                
                iteration += 1
                logger.info(f"Polling iteration {iteration}")
                
                messages = self.poll_messages()
                
                if not messages:
                    logger.info("No messages received, continuing to poll...")
                    continue
                
                for message in messages:
                    if not self.running:
                        break
                    self.process_message(message)
                
                if iteration % 10 == 0:
                    self.print_stats()
                    
        except KeyboardInterrupt:
            logger.info("Received interrupt signal, stopping worker...")
        except Exception as e:
            logger.error(f"Unexpected error in worker: {str(e)}")
        finally:
            self.running = False
            self.print_stats()
            logger.info("Worker stopped")
    
    def stop(self):
        logger.info("Stopping worker...")
        self.running = False


class BatchSQSWorker(SQSWorker):
    def __init__(self, *args, batch_size: int = 10, **kwargs):
        super().__init__(*args, **kwargs)
        self.batch_size = batch_size
        self.message_batch = []
    
    def process_batch(self):
        if not self.message_batch:
            return
        
        logger.info(f"Processing batch of {len(self.message_batch)} messages")
        
        for message in self.message_batch:
            self.process_message(message)
        
        self.message_batch = []
    
    def run(self, max_iterations: Optional[int] = None):
        self.running = True
        iteration = 0
        
        logger.info(f"Starting Batch SQS worker for queue: {self.queue_url}")
        
        try:
            while self.running:
                if max_iterations and iteration >= max_iterations:
                    logger.info(f"Reached max iterations: {max_iterations}")
                    break
                
                iteration += 1
                messages = self.poll_messages()
                
                if messages:
                    self.message_batch.extend(messages)
                
                if len(self.message_batch) >= self.batch_size:
                    self.process_batch()
                
                if iteration % 10 == 0:
                    self.print_stats()
                    
        except KeyboardInterrupt:
            logger.info("Received interrupt signal, processing remaining batch...")
            self.process_batch()
        except Exception as e:
            logger.error(f"Unexpected error in worker: {str(e)}")
        finally:
            self.running = False
            self.print_stats()
            logger.info("Batch worker stopped")


